function tam_table_exists(PDO $pdo,string $table): bool{static $cache=[];if(!preg_match('/^[a-zA-Z0-9_]+$/',$table))return false;if(array_key_exists($table,$cache))return $cache[$table];try{$stmt=$pdo->prepare('SELECT COUNT(*) FROM information_schema.TABLES WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME=:t');$stmt->execute(['t'=>$table]);return $cache[$table]=((int)$stmt->fetchColumn())>0;}catch(Throwable){return $cache[$table]=false;}}
function tam_metric(?PDO $pdo,string $key,string $label,array $tables,string $sql,float|int $fallback=0): array{if(!$pdo)return compact('key','label','tables')+['value'=>$fallback,'source'=>'fallback'];foreach($tables as $table){if(!tam_table_exists($pdo,(string)$table))return compact('key','label','tables')+['value'=>$fallback,'source'=>'missing'];}try{$v=$pdo->query($sql)->fetchColumn();return compact('key','label','tables')+['value'=>is_numeric($v)?(float)$v:$fallback,'source'=>'live'];}catch(Throwable){return compact('key','label','tables')+['value'=>$fallback,'source'=>'error'];}}
function tam_n(float|int $v,int $d=0): string{return number_format((float)$v,$d);}function tam_money_cents(float|int $c,bool $compact=false): string{$a=((float)$c)/100;if($compact){$abs=abs($a);if($abs>=1000000000)return '$'.number_format($a/1000000000,2).'B';if($abs>=1000000)return '$'.number_format($a/1000000,1).'M';if($abs>=1000)return '$'.number_format($a/1000,1).'K';}return '$'.number_format($a,0);}function tam_money(float|int $a,bool $compact=false): string{return tam_money_cents(((float)$a)*100,$compact);}function tam_pct(float $v,int $d=1): string{return number_format($v*100,$d).'%';}function tam_source_label(string $s): string{return match($s){'live'=>'Live DB','missing'=>'Table pending','error'=>'Query fallback',default=>'Fallback'};}function tam_source_class(string $s): string{return $s==='live'?'is-live':'is-fallback';}

$pdo=null;$dbStatus='connected';try{$pdo=mg_db();}catch(Throwable){$dbStatus='fallback';}
$defs=[
 ['total_merchants','Total merchant workspaces',['merchant_workspaces'],"SELECT COUNT(*) FROM merchant_workspaces"],
 ['active_merchants','Active merchant workspaces',['merchant_workspaces'],"SELECT COUNT(*) FROM merchant_workspaces WHERE status='active'"],
 ['active_locations','Active merchant locations',['merchant_locations'],"SELECT COUNT(*) FROM merchant_locations WHERE status='active'"],
 ['active_rewards','Active reward templates',['reward_templates'],"SELECT COUNT(*) FROM reward_templates WHERE status='active'"],
 ['total_campaigns','Total campaigns',['campaigns'],"SELECT COUNT(*) FROM campaigns"],
 ['active_campaigns','Active campaigns',['campaigns'],"SELECT COUNT(*) FROM campaigns WHERE status='active'"],
 ['campaign_contacts','Campaign contacts',['campaign_contacts'],"SELECT COUNT(*) FROM campaign_contacts"],
 ['wallet_items','Wallet rewards issued',['wallet_items'],"SELECT COUNT(*) FROM wallet_items"],
 ['wallet_redeemed','Wallet rewards redeemed',['wallet_items'],"SELECT COUNT(*) FROM wallet_items WHERE status='redeemed'"],
 ['wallet_value_cents','Wallet value issued',['wallet_items'],"SELECT COALESCE(SUM(value_cents_snapshot),0) FROM wallet_items"],
 ['wallet_30d_value_cents','Wallet value issued, 30 days',['wallet_items'],"SELECT COALESCE(SUM(value_cents_snapshot),0) FROM wallet_items WHERE issued_at>=DATE_SUB(NOW(),INTERVAL 30 DAY)"],
 ['microgift_instances','Microgift instances issued',['microgift_instances'],"SELECT COUNT(*) FROM microgift_instances"],
 ['microgift_face_value_cents','Microgift face value issued',['microgift_instances'],"SELECT COALESCE(SUM(face_value_cents),0) FROM microgift_instances"],
 ['microgift_30d_value_cents','Microgift value issued, 30 days',['microgift_instances'],"SELECT COALESCE(SUM(face_value_cents),0) FROM microgift_instances WHERE issued_at>=DATE_SUB(NOW(),INTERVAL 30 DAY)"],
 ['claims_total','Microgift claims',['microgift_claims'],"SELECT COUNT(*) FROM microgift_claims"],
 ['redemptions_total','Microgift redemptions',['microgift_redemptions'],"SELECT COUNT(*) FROM microgift_redemptions WHERE status='completed'"],
 ['redemption_value_cents','Redeemed value',['microgift_redemptions'],"SELECT COALESCE(SUM(amount_cents),0) FROM microgift_redemptions WHERE status='completed'"],
 ['redemption_30d_value_cents','Redeemed value, 30 days',['microgift_redemptions'],"SELECT COALESCE(SUM(amount_cents),0) FROM microgift_redemptions WHERE status='completed' AND redeemed_at>=DATE_SUB(NOW(),INTERVAL 30 DAY)"],
 ['pppm_items','PPPM lifecycle items',['pppm_items'],"SELECT COUNT(*) FROM pppm_items"],
 ['pppm_value_cents','PPPM value tracked',['pppm_items'],"SELECT COALESCE(SUM(value_cents_snapshot),0) FROM pppm_items"],
 ['psr_records','Purchase signal records',['purchase_signal_records'],"SELECT COUNT(*) FROM purchase_signal_records"],
 ['psr_outstanding_value_cents','Outstanding PSR value',['purchase_signal_records'],"SELECT COALESCE(SUM(estimated_value_cents),0) FROM purchase_signal_records WHERE status='outstanding'"],
 ['psr_committed_value_cents','Committed-demand PSR value',['purchase_signal_records'],"SELECT COALESCE(SUM(estimated_value_cents),0) FROM purchase_signal_records WHERE signal_type='committed_demand' AND status IN ('outstanding','redeemed')"],
];
$metrics=[];foreach($defs as $d){[$key,$label,$tables,$sql]=$d;$metrics[$key]=tam_metric($pdo,$key,$label,$tables,$sql,0);} $v=static fn(string $k): float=>(float)($metrics[$k]['value']??0); $src=static fn(string $k): string=>(string)($metrics[$k]['source']??'fallback');

$totalMerchants=$v('total_merchants');$activeMerchants=$v('active_merchants');$merchantBasis=max(1,$activeMerchants?:$totalMerchants);$locations=$v('active_locations');$campaigns=$v('total_campaigns');$contacts=$v('campaign_contacts');$wallet=$v('wallet_items');$microgifts=$v('microgift_instances');$pppm=$v('pppm_items');$issuedValue=$v('wallet_value_cents')+$v('microgift_face_value_cents')+$v('pppm_value_cents');$signalValue=$v('psr_outstanding_value_cents')+$v('psr_committed_value_cents');$trackedValue=$issuedValue+$signalValue;$last30=$v('wallet_30d_value_cents')+$v('microgift_30d_value_cents')+$v('redemption_30d_value_cents');$redeemed=$v('wallet_redeemed')+$v('redemptions_total');$redeemBase=$wallet+$microgifts;$avgTicketCents=($wallet+$microgifts+$pppm)>0?max(500,$issuedValue/max(1,$wallet+$microgifts+$pppm)):2500;$avgTicketDollars=max(15,min(75,$avgTicketCents/100));$monthlyPromoVolume=max(750,min(3000,$avgTicketDollars*60));$redemptionRate=$redeemBase>0?min(1,max(0,$redeemed/$redeemBase)):.32;$hasActivity=($trackedValue+$contacts+$redeemed)>0;

$targetMerchants=250000;$subArpu=79;$distributionArpu=25;$takeRate=.15;$annualSaas=$subArpu*12;$annualDist=$distributionArpu*12;$annualTxn=$monthlyPromoVolume*12*$takeRate;$annualPerMerchant=$annualSaas+$annualTxn+$annualDist;$saasTam=$targetMerchants*$annualSaas;$txnTam=$targetMerchants*$annualTxn;$distTam=$targetMerchants*$annualDist;$totalTam=$saasTam+$txnTam+$distTam;$currentRunRate=($activeMerchants?:$totalMerchants)*$annualPerMerchant;$penetration=$targetMerchants>0?$activeMerchants/$targetMerchants:0;

$forecastCards=[['Predicted bottom-up TAM',tam_money($totalTam,true),tam_n($targetMerchants).' ICP merchants × '.tam_money($annualPerMerchant).' annual platform revenue per merchant'],['SaaS ARR layer',tam_money($saasTam,true),tam_money($subArpu).'/mo Promotional CRM subscription'],['Transaction layer',tam_money($txnTam,true),tam_money($monthlyPromoVolume).'/mo promo volume × '.tam_pct($takeRate,0).' take rate'],['Distribution layer',tam_money($distTam,true),tam_money($distributionArpu).'/mo campaign stamps and controlled distribution']];
$currentCards=[['Merchant workspaces',tam_n($totalMerchants),tam_n($activeMerchants).' active',$src('total_merchants')],['Merchant locations',tam_n($locations),tam_n($locations/max(1,$merchantBasis),2).' locations per merchant',$src('active_locations')],['Campaigns',tam_n($campaigns),tam_n($v('active_campaigns')).' active campaigns',$src('total_campaigns')],['Campaign contacts',tam_n($contacts),tam_n($contacts/max(1,$merchantBasis),1).' contacts per merchant basis',$src('campaign_contacts')],['Rewards + Microgifts',tam_n($wallet+$microgifts),tam_money_cents($v('wallet_value_cents')+$v('microgift_face_value_cents'),true).' issued value',($src('wallet_items')==='live'||$src('microgift_instances')==='live')?'live':'fallback'],['Claims + Redemptions',tam_n($redeemed),tam_pct($redemptionRate).' observed/fallback redemption rate',($src('redemptions_total')==='live'||$src('claims_total')==='live')?'live':'fallback'],['PSR demand signals',tam_n($v('psr_records')),tam_money_cents($signalValue,true).' outstanding/committed value',$src('psr_records')],['Tracked value base',tam_money_cents($trackedValue,true),tam_money_cents($last30,true).' last 30 days tracked/redeemed',$hasActivity?'live':'fallback']];
$dataRows=[['Merchants',tam_n($totalMerchants).' total / '.tam_n($activeMerchants).' active','merchant_workspaces','Validates merchant onboarding base and penetration against ICP merchant count.'],['Locations',tam_n($locations),'merchant_locations','Supports multi-location expansion and location-level claim scope.'],['Campaigns',tam_n($campaigns),'campaigns','Measures Promotional CRM usage and campaign creation velocity.'],['Contacts',tam_n($contacts),'campaign_contacts / merchant_crm_contacts','Shows the customer graph created by promotions, QR drops, and campaigns.'],['Rewards issued',tam_n($wallet+$microgifts),'wallet_items / microgift_instances','Feeds average value, redemption rate, transaction revenue, and repeat campaign assumptions.'],['Redeemed value',tam_money_cents($v('redemption_value_cents'),true),'microgift_redemptions','Shows commerce completion and claim-to-redemption monetization.'],['PSR demand',tam_money_cents($signalValue,true),'purchase_signal_records','Feeds future demand intelligence and committed-demand value forecast.'],['PPPM lifecycle',tam_n($pppm).' items','pppm_items','Shows lifecycle tracking from issue through redemption, expiration, refund, and reuse.']];
$ladder=[];foreach([.005,.01,.03,.10,1.00] as $p){$m=(int)round($targetMerchants*$p);$arr=$m*$annualPerMerchant;$ladder[]=['label'=>$p===1.0?'Full ICP TAM':tam_pct($p,$p<.01?1:0).' penetration','merchants'=>$m,'arr'=>$arr,'bar'=>$totalTam>0?min(100,($arr/$totalTam)*100):0];}
